@FunctionalInterface
public interface ThrowingFunction<T, R, E extendsThrowable> {
    static <T, R, E extendsThrowable> Function<T, R> unchecked(ThrowingFunction<T, R, E> f) {
        return t -> {
            try {
                return f.apply(t);
            } catch (Throwable e) {
                throw new RuntimeException(e);
            }
        };
    }
    R apply(T t) throws E;
}

